package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.*;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.contract.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/internal/supplier/v1/contract-approval/events")public class ContractApprovalEventOpenApiController {private final ContractApprovalEventConsumerApplicationService service;public ContractApprovalEventOpenApiController(ContractApprovalEventConsumerApplicationService service){this.service=service;}@PostMapping public ApiResponse<Void> consume(@Valid @RequestBody Body b,HttpServletRequest r){if(!"IAM".equals(r.getHeader("X-Source-System")))throw new BusinessException(ErrorCode.FORBIDDEN,"来源系统必须为IAM");String code=r.getHeader("X-Event-Code");if(code==null||code.isBlank())throw new BusinessException(ErrorCode.VALIDATION_FAILED,"缺少事件编码");service.consume(new ContractApprovalEvent(code,"IAM",b.eventType(),b.contractId(),b.contractVersion(),b.approved(),b.comment()));return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}public record Body(@NotBlank String eventType,@Positive long contractId,@PositiveOrZero int contractVersion,boolean approved,String comment){}}
